import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"服装与纺织行业专项模板","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/garment/index.md","filePath":"zh/industry/garment/index.md"}'),n={name:"zh/industry/garment/index.md"};function o(h,t,l,s,i,c){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="服装与纺织行业专项模板" tabindex="-1">服装与纺织行业专项模板 <a class="header-anchor" href="#服装与纺织行业专项模板" aria-label="Permalink to &quot;服装与纺织行业专项模板&quot;">​</a></h1><blockquote><p><strong>行业背景：</strong> 全球服装供应链以劳动密集型生产为主，高度集中于南亚（孟加拉国、印度、巴基斯坦）、东南亚（越南、柬埔寨、缅甸）和中国。该行业历史上存在严重的劳工风险（Rana Plaza）、化学品合规问题（有毒染料）和分包不透明问题。</p></blockquote><h2 id="本节工具" tabindex="-1">本节工具 <a class="header-anchor" href="#本节工具" aria-label="Permalink to &quot;本节工具&quot;">​</a></h2><ul><li><a href="./saq.html">服装行业供应商自评问卷（SAQ-GAR）</a></li><li><a href="./audit-checklist.html">服装行业审核前文件请求清单</a></li><li><a href="./worker-interview.html">工人访谈指引（服装专版）</a></li></ul><hr><h2 id="行业风险优先级矩阵" tabindex="-1">行业风险优先级矩阵 <a class="header-anchor" href="#行业风险优先级矩阵" aria-label="Permalink to &quot;行业风险优先级矩阵&quot;">​</a></h2><table tabindex="0"><thead><tr><th>风险类别</th><th>风险等级</th><th>核心指标</th></tr></thead><tbody><tr><td>过度加班 / 强制加班</td><td>🔴 极高</td><td>旺季工时、加班拒绝权</td></tr><tr><td>工资欠付 / 扣薪</td><td>🔴 极高</td><td>最低工资合规、奖金扣押</td></tr><tr><td>分包 / 未申报工厂</td><td>🔴 极高</td><td>订单流向、外包工厂名单</td></tr><tr><td>童工 / 强迫劳动</td><td>🔴 极高</td><td>年龄核验、债务束缚</td></tr><tr><td>化学品（REACH/ZDHC）</td><td>🟠 高</td><td>MRSL合规、废水检测</td></tr><tr><td>建筑安全</td><td>🟠 高</td><td>使用许可证、结构检查记录</td></tr><tr><td>工会权利</td><td>🟠 高</td><td>集体谈判、工人代表</td></tr><tr><td>用水 / 染整废水</td><td>🟡 中高</td><td>污水处理设施、排放监测</td></tr><tr><td>棉花溯源（新疆）</td><td>🔴 极高（特定市场）</td><td>原料采购来源文件</td></tr></tbody></table><hr><h2 id="关键法规参照" tabindex="-1">关键法规参照 <a class="header-anchor" href="#关键法规参照" aria-label="Permalink to &quot;关键法规参照&quot;">​</a></h2><table tabindex="0"><thead><tr><th>法规 / 标准</th><th>适用场景</th></tr></thead><tbody><tr><td><strong>ILO 核心公约</strong>（C87、C98、C105、C138、C182）</td><td>劳工基本权利（全球适用）</td></tr><tr><td><strong>BSCI / amfori</strong></td><td>欧洲采购商要求</td></tr><tr><td><strong>WRAP</strong></td><td>美国市场合规</td></tr><tr><td><strong>SA8000</strong></td><td>管理体系认证</td></tr><tr><td><strong>ZDHC MRSL</strong></td><td>有害化学品管控（纺织）</td></tr><tr><td><strong>REACH 附件XVII</strong></td><td>欧盟禁用物质</td></tr><tr><td><strong>OEKO-TEX Standard 100</strong></td><td>成品检测认证</td></tr><tr><td><strong>《强迫劳动预防法》（UFLPA）</strong></td><td>美国进口，新疆棉排除</td></tr><tr><td><strong>《欧盟供应链法》（CSDD）</strong></td><td>欧洲采购商尽职调查义务</td></tr></tbody></table><hr><h2 id="参考案例" tabindex="-1">参考案例 <a class="header-anchor" href="#参考案例" aria-label="Permalink to &quot;参考案例&quot;">​</a></h2><ul><li><a href="/zh/cases/csr/rana-plaza.html">Rana Plaza 大楼坍塌（2013）</a> — 建筑安全、分包隐瞒</li></ul>',13)])])}const b=d(n,[["render",o]]);export{g as __pageData,b as default};
